#include <math.h>
#include <stdio.h>
#include <stdlib.h>
#include <string.h>

typedef struct latLong
{
    float lat;
    float lng;
} LatLong;

typedef struct record
{
    char recString[49];
    float distance;
} Record;

typedef struct {
    Record *data;
    int size;
    int capacity;
} RecordVector;

typedef struct {
    LatLong *data;
    int size;
    int capacity;
} LatLongVector;

void RecordVector_init(RecordVector *vec) {
    vec->size = 0;
    vec->capacity = 16;
    vec->data = (Record *)malloc(vec->capacity * sizeof(Record));
    if (!vec->data) {
        fprintf(stderr, "Failed to allocate RecordVector\n");
        exit(1);
    }
}

void RecordVector_push_back(RecordVector *vec, Record val) {
    if (vec->size == vec->capacity) {
        vec->capacity *= 2;
        vec->data = (Record *)realloc(vec->data, vec->capacity * sizeof(Record));
        if (!vec->data) {
            fprintf(stderr, "Failed to reallocate RecordVector\n");
            exit(1);
        }
    }
    vec->data[vec->size++] = val;
}

void RecordVector_free(RecordVector *vec) {
    free(vec->data);
    vec->data = NULL;
    vec->size = 0;
    vec->capacity = 0;
}

void LatLongVector_init(LatLongVector *vec) {
    vec->size = 0;
    vec->capacity = 16;
    vec->data = (LatLong *)malloc(vec->capacity * sizeof(LatLong));
    if (!vec->data) {
        fprintf(stderr, "Failed to allocate LatLongVector\n");
        exit(1);
    }
}

void LatLongVector_push_back(LatLongVector *vec, LatLong val) {
    if (vec->size == vec->capacity) {
        vec->capacity *= 2;
        vec->data = (LatLong *)realloc(vec->data, vec->capacity * sizeof(LatLong));
        if (!vec->data) {
            fprintf(stderr, "Failed to reallocate LatLongVector\n");
            exit(1);
        }
    }
    vec->data[vec->size++] = val;
}

void LatLongVector_free(LatLongVector *vec) {
    free(vec->data);
    vec->data = NULL;
    vec->size = 0;
    vec->capacity = 0;
}

void NearestNeighbor(LatLong *d_locations,
                     float *d_distances,
                     const int numRecords,
                     const float lat,
                     const float lng) {
#pragma omp parallel for
    for (int globalId = 0; globalId < numRecords; globalId++) {
        LatLong *latLong = d_locations + globalId;
        float *dist = d_distances + globalId;
        *dist = (float)sqrt((lat - latLong->lat) * (lat - latLong->lat) + (lng - latLong->lng) * (lng - latLong->lng));
    }
}

float *OpenClFindNearestNeighbors(
    int numRecords,
    LatLongVector *locations, float lat, float lng) {

    float *distances = (float *)malloc(sizeof(float) * numRecords);
    if (!distances) {
        fprintf(stderr, "Failed to allocate distances array\n");
        exit(1);
    }

    NearestNeighbor(locations->data, distances, numRecords, lat, lng);

    return distances;
}

void findLowest(RecordVector *records, float *distances, int numRecords, int topN) {
    int i, j;
    float val;
    int minLoc;
    Record tempRec;
    float tempDist;

    for (i = 0; i < topN; i++) {
        minLoc = i;
        for (j = i; j < numRecords; j++) {
            val = distances[j];
            if (val < distances[minLoc])
                minLoc = j;
        }

        tempRec = records->data[i];
        records->data[i] = records->data[minLoc];
        records->data[minLoc] = tempRec;

        tempDist = distances[i];
        distances[i] = distances[minLoc];
        distances[minLoc] = tempDist;

        records->data[i].distance = distances[i];
    }
}

int loadData(char *filename, RecordVector *records, LatLongVector *locations, const char *data_folder) {
    FILE *flist, *fp;
    int i = 0;
    char dbname[64], db_fullname[128];
    int recNum = 0;

    flist = fopen(filename, "r");
    if (!flist) {
        fprintf(stderr, "Error opening file list: %s\n", filename);
        exit(1);
    }
    while (fscanf(flist, "%63s\n", dbname) == 1) {
        snprintf(db_fullname, sizeof(db_fullname), "%s/%s", data_folder, dbname);
        fp = fopen(db_fullname, "r");
        if (!fp) {
            printf("error opening a db (%s)\n", db_fullname);
            exit(1);
        }

        while (1) {
            Record record;
            LatLong latLong;
            if (!fgets(record.recString, 49, fp))
                break;
            int c = fgetc(fp); // consume newline or separator
            (void)c;
            if (feof(fp))
                break;

            char substr[6];

            for (i = 0; i < 5; i++)
                substr[i] = *(record.recString + i + 28);
            substr[5] = '\0';
            latLong.lat = atof(substr);

            for (i = 0; i < 5; i++)
                substr[i] = *(record.recString + i + 33);
            substr[5] = '\0';
            latLong.lng = atof(substr);

            LatLongVector_push_back(locations, latLong);
            RecordVector_push_back(records, record);
            recNum++;
        }
        fclose(fp);
    }
    fclose(flist);
    return recNum;
}

int parseCommandline(int argc, char *argv[], char *filename, int *r, float *lat, float *lng,
                     int *q, int *t, int *p, int *d, char **data_folder) {
    int i;
    if (argc < 2)
        return 1;
    strncpy(filename, argv[1], 100);
    char flag;

    for (i = 1; i < argc; i++) {
        if (argv[i][0] == '-') {
            flag = argv[i][1];
            switch (flag) {
            case 'r':
                i++;
                *r = atoi(argv[i]);
                break;
            case 'l':
                if (argv[i][2] == 'a') {
                    *lat = atof(argv[i + 1]);
                } else {
                    *lng = atof(argv[i + 1]);
                }
                i++;
                break;
            case 'h':
                return 1;
            case 'q':
                *q = 1;
                break;
            case 't':
                *t = 1;
                break;
            case 'p':
                i++;
                *p = atoi(argv[i]);
                break;
            case 'd':
                i++;
                *d = atoi(argv[i]);
                break;
            case 'f':
                i++;
                *data_folder = argv[i];
                break;
            }
        }
    }
    if ((*d >= 0 && *p < 0) || (*p >= 0 && *d < 0))
        return 1;
    return 0;
}

void printUsage() {
    printf("Nearest Neighbor Usage\n");
    printf("\n");
    printf("nearestNeighbor [filename] -r [int] -lat [float] -lng [float] [-hqt] [-p [int] -d [int]]\n");
    printf("\n");
    printf("example:\n");
    printf("$ ./nearestNeighbor filelist.txt -r 5 -lat 30 -lng 90\n");
    printf("\n");
    printf("filename     the filename that lists the data input files\n");
    printf("-r [int]     the number of records to return (default: 10)\n");
    printf("-lat [float] the latitude for nearest neighbors (default: 0)\n");
    printf("-lng [float] the longitude for nearest neighbors (default: 0)\n");
    printf("\n");
    printf("-h, --help   Display the help file\n");
    printf("-q           Quiet mode. Suppress all text output.\n");
    printf("-t           Print timing information.\n");
    printf("\n");
    printf("-p [int]     Choose the platform (must choose both platform and device)\n");
    printf("-d [int]     Choose the device (must choose both platform and device)\n");
    printf("\n");
    printf("\n");
    printf("Notes: 1. The filename is required as the first parameter.\n");
    printf("       2. If you declare either the device or the platform,\n");
    printf("          you must declare both.\n\n");
}

int main(int argc, char *argv[]) {
    RecordVector records;
    LatLongVector locations;
    float *recordDistances;

    int i;

    char filename[100];
    int resultsCount = 10, quiet = 0, timing = 0, platform = -1, device = -1;
    float lat = 0.0, lng = 0.0;
    char *data_folder = (char *)".";

    RecordVector_init(&records);
    LatLongVector_init(&locations);

    if (parseCommandline(argc, argv, filename, &resultsCount, &lat, &lng,
                         &quiet, &timing, &platform, &device, &data_folder)) {
        printUsage();
        RecordVector_free(&records);
        LatLongVector_free(&locations);
        return 0;
    }

    int numRecords = loadData(filename, &records, &locations, data_folder);

    if (!quiet) {
        printf("Number of records: %d\n", numRecords);
        printf("Finding the %d closest neighbors.\n", resultsCount);
    }

    if (resultsCount > numRecords)
        resultsCount = numRecords;

    recordDistances = OpenClFindNearestNeighbors(numRecords, &locations, lat, lng);

    findLowest(&records, recordDistances, numRecords, resultsCount);

    if (!quiet)
        for (i = 0; i < resultsCount; i++) {
            printf("%s --> Distance=%f\n", records.data[i].recString, records.data[i].distance);
        }
    free(recordDistances);
    RecordVector_free(&records);
    LatLongVector_free(&locations);
    return 0;
}
